const item = $input.first();
const binaryField = item.binary?.data;
if (!binaryField?.data) {
  throw new Error('Expected binary data in field "data" from the file read node.');
}

const text = Buffer.from(binaryField.data, 'base64').toString('utf8');
const normalized = text.replace(/\r\n/g, '\n').trim();
const chunkSize = 1200;
const overlap = 200;
const step = Math.max(1, chunkSize - overlap);
const filename = binaryField.fileName || 'unknown.txt';

const chunks = [];
for (let start = 0; start < normalized.length; start += step) {
  const chunk = normalized.slice(start, start + chunkSize).trim();
  if (!chunk) continue;
  chunks.push(chunk);
  if (start + chunkSize >= normalized.length) break;
}

return chunks.map((chunk, index) => ({
  json: {
    filename,
    content: chunk,
    chunk_index: index + 1,
    total_chunks: chunks.length
  }
}));

const filename = $json.filename;
const titlePrefix = filename.replace(/\.[^/.]+$/, '');
const ingestTimestamp = new Date().toISOString();

return {
  json: {
    source: 'file_ingest',
    category: 'project_note',
    title: `${titlePrefix} :: chunk ${String($json.chunk_index).padStart(2, '0')}`,
    content: $json.content,
    tags: [],
    filename,
    chunk_index: $json.chunk_index,
    total_chunks: $json.total_chunks,
    ingested_at: ingestTimestamp,
    metadata_json: {
      filename,
      chunk_index: $json.chunk_index,
      total_chunks: $json.total_chunks,
      ingested_at: ingestTimestamp
    }
  }
};
